package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.io.StringWriter;

class JsonWriterTest {

    private JsonWriter jsonWriter;

    @BeforeEach
    void setUp() {
        jsonWriter = new JsonWriter(new StringWriter());
    }

    @Test
    void testSetIndent_emptyString_setsIndentNullAndSeparatorColon() {
        jsonWriter.setIndent("");
        assertNull(getIndent(jsonWriter));
        assertEquals(":", getSeparator(jsonWriter));
    }

    @Test
    void testSetIndent_nonEmptyString_setsIndentAndSeparatorColonSpace() {
        String indentValue = "  ";
        jsonWriter.setIndent(indentValue);
        assertEquals(indentValue, getIndent(jsonWriter));
        assertEquals(": ", getSeparator(jsonWriter));
    }

    private String getIndent(JsonWriter writer) {
        try {
            var field = JsonWriter.class.getDeclaredField("indent");
            field.setAccessible(true);
            return (String) field.get(writer);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private String getSeparator(JsonWriter writer) {
        try {
            var field = JsonWriter.class.getDeclaredField("separator");
            field.setAccessible(true);
            return (String) field.get(writer);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
